const requiredFields = ['item_id', 'source_type', 'source_name', 'title', 'content_text', 'summary'];
const missingFields = requiredFields.filter((field) => !String($json[field] || '').trim());
if (missingFields.length) {
  throw new Error(`Enriched item missing required fields: ${missingFields.join(', ')}`);
}

const embeddingBaseUrl = String($env.EMBEDDING_BASE_URL || '').trim().replace(/\/+$/, '');
const embeddingModel = String($env.EMBEDDING_MODEL || '').trim();
const embeddingApiKey = String($env.EMBEDDING_API_KEY || '').trim();
const qdrantCollection = String($env.QDRANT_COLLECTION || 'article_embeddings').trim() || 'article_embeddings';
const qdrantVectorSize = Number($env.QDRANT_VECTOR_SIZE || 0);

if (!embeddingBaseUrl) {
  throw new Error('EMBEDDING_BASE_URL is required for 03_qdrant_gate');
}
if (!embeddingModel) {
  throw new Error('EMBEDDING_MODEL is required for 03_qdrant_gate');
}
if (!embeddingApiKey) {
  throw new Error('EMBEDDING_API_KEY is required for 03_qdrant_gate');
}
if (!Number.isInteger(qdrantVectorSize) || qdrantVectorSize <= 0) {
  throw new Error('QDRANT_VECTOR_SIZE must be a positive integer');
}

const embeddingInput = [
  String($json.title || '').trim(),
  String($json.summary || '').trim(),
  String($json.content_text || '').trim()
].filter(Boolean).join('\n\n').slice(0, 12000);

if (embeddingInput.length < 80) {
  throw new Error('Embedding input is too short for reliable dedupe; expected at least 80 characters after normalization');
}

return {
  json: {
    ...$json,
    embedding_base_url: embeddingBaseUrl,
    embedding_model: embeddingModel,
    qdrant_base_url: 'http://qdrant:6333',
    qdrant_collection: qdrantCollection,
    qdrant_vector_size: qdrantVectorSize,
    embedding_input: embeddingInput
  }
};

return {
  json: {
    ...$json,
    embedding_endpoint: `${$json.embedding_base_url}/embeddings`,
    embedding_request: {
      model: $json.embedding_model,
      input: $json.embedding_input
    }
  }
};

const original = $('Build Embedding Request').item.json || {};
const embedding = $json?.data?.[0]?.embedding;
if (!Array.isArray(embedding)) {
  throw new Error('Embedding response did not include data[0].embedding');
}
if (embedding.length !== Number(original.qdrant_vector_size)) {
  throw new Error(`Embedding vector length ${embedding.length} does not match QDRANT_VECTOR_SIZE ${original.qdrant_vector_size}`);
}

return {
  json: {
    ...original,
    embedding,
    qdrant_search_endpoint: `${original.qdrant_base_url}/collections/${encodeURIComponent(original.qdrant_collection)}/points/search`,
    qdrant_search_payload: {
      vector: embedding,
      limit: 1,
      with_payload: true
    }
  }
};

const original = $('Build Qdrant Search Request').item.json || {};
const matches = Array.isArray($json?.result)
  ? $json.result
  : Array.isArray($json)
    ? $json
    : [];
const match = matches[0] || null;

let dedupeAction = 'full_push';
let notificationMode = 'full';
let shouldWriteToVault = true;
let shouldNotify = true;
let shouldUpsertQdrant = true;

if (match && match.score >= 0.97) {
  dedupeAction = 'silent';
  notificationMode = 'silent';
  shouldWriteToVault = false;
  shouldNotify = false;
  shouldUpsertQdrant = false;
} else if (match && match.score >= 0.85) {
  dedupeAction = 'diff_push';
  notificationMode = 'incremental';
}

return {
  json: {
    ...original,
    dedupe_action: dedupeAction,
    notification_mode: notificationMode,
    should_write_to_vault: shouldWriteToVault,
    should_notify: shouldNotify,
    should_upsert_qdrant: shouldUpsertQdrant,
    matched_payload: match?.payload || null,
    matched_score: Number(match?.score || 0),
    status: dedupeAction === 'silent' ? 'deduped' : original.status
  }
};

const toDeterministicUuid = (value) => {
  const hex = String(value || '').toLowerCase().replace(/[^0-9a-f]/g, '');
  const padded = (hex + '00000000000000000000000000000000').slice(0, 32);
  return `${padded.slice(0, 8)}-${padded.slice(8, 12)}-${padded.slice(12, 16)}-${padded.slice(16, 20)}-${padded.slice(20, 32)}`;
};

const qdrantPointId = toDeterministicUuid($json.item_id);

return {
  json: {
    ...$json,
    qdrant_point_id: qdrantPointId,
    qdrant_upsert_endpoint: `${$json.qdrant_base_url}/collections/${encodeURIComponent($json.qdrant_collection)}/points`,
    qdrant_upsert_payload: {
      points: [
        {
          id: qdrantPointId,
          vector: $json.embedding,
          payload: {
            item_id: $json.item_id,
            source_type: $json.source_type,
            source_name: $json.source_name,
            title: $json.title,
            canonical_url: $json.canonical_url,
            published_at: $json.published_at,
            score: $json.score,
            category: $json.category,
            summary: $json.summary,
            dedupe_action: $json.dedupe_action,
            matched_score: $json.matched_score,
            tags: $json.tags,
            content_hash: $json.content_hash
          }
        }
      ]
    }
  }
};

const original = $('Build Qdrant Upsert Payload').item.json || {};
return {
  json: {
    ...original,
    qdrant_operation: 'upserted',
    qdrant_upsert_response: $json
  }
};
